  KEY `rapor_items_rapor_id_kategori_index` (`rapor_id`, `kategori`)
) ENGINE=InnoDB DEFAULT CHARSET=utf8mb4 COLLATE=utf8mb4_unicode_ci;


DROP TABLE IF EXISTS `rapors`;
CREATE TABLE `rapors` (
